const Handle_UI = {
    switchServer(isTraining, config){
        if (isTraining == true){
            window.alert("Current in training. No allow to switch user type.")
            return;
        }

        const serverTypeBtn = document.querySelector('#switch-type button.server');
        const clientTypeBtn = document.querySelector('#switch-type button.client');
        serverTypeBtn.disabled = true;
        serverTypeBtn.classList.add('selected');
        serverTypeBtn.classList.remove('unselected');
        clientTypeBtn.disabled = false;
        clientTypeBtn.classList.add('unselected');
        clientTypeBtn.classList.remove('selected');

        document.getElementById('client-side').classList.add('hidden');
        document.getElementById('server-side').classList.remove('hidden');
        config = CONFIG['server'];
        Handle_UI.setTrainingButtonsState(false); 
        console.log("Switch type: " + config.typeText);
    },

    switchClient(isTraining){
        if (isTraining == true){
            window.alert("Current in training. No allow to switch user type.")
            return;
        }

        const serverTypeBtn = document.querySelector('#switch-type button.server');
        const clientTypeBtn = document.querySelector('#switch-type button.client');
        serverTypeBtn.disabled = false;
        serverTypeBtn.classList.add('unselected');
        serverTypeBtn.classList.remove('selected');
        clientTypeBtn.disabled = true;
        clientTypeBtn.classList.add('selected');
        clientTypeBtn.classList.remove('unselected');
        
        document.getElementById('client-side').classList.remove('hidden');
        document.getElementById('server-side').classList.add('hidden');
        
        config = CONFIG['client'];
        Handle_UI.setTrainingButtonsState(false); 
        console.log("Switch type: " + config.typeText);
    },

    setTrainingButtonsState(isTrainingActive) {
        const prefix = config.typeText;
        const startBtn = document.querySelector(`#${prefix}-side .training-control .startTrainingBtn`);
        const stopBtn = document.querySelector(`#${prefix}-side .training-control .stopTrainingBtn`);
        const simulatorStartBtn = document.querySelector(`#server-side .simulator-control .startTrainingBtn`);
        const simulatorStopBtn = document.querySelector(`#server-side .simulator-control .stopTrainingBtn`);
        
        if (!startBtn || !stopBtn) return;
        
        if (isTrainingActive) {
            // Training is active → Start disabled, Stop enabled
            startBtn.disabled = true;
            startBtn.classList.remove('selected');
            startBtn.classList.add('unselected');
            
            stopBtn.disabled = false;
            stopBtn.classList.remove('unselected');
            stopBtn.classList.add('selected');

            simulatorStartBtn.disabled = true;
            simulatorStartBtn.classList.remove('selected');
            simulatorStartBtn.classList.add('unselected');
            
            simulatorStopBtn.disabled = false;
            simulatorStopBtn.classList.remove('unselected');
            simulatorStopBtn.classList.add('selected');
        } else {
            // Training is inactive → Start enabled, Stop disabled
            startBtn.disabled = false;
            startBtn.classList.remove('unselected');
            startBtn.classList.add('selected');
            
            stopBtn.disabled = true;
            stopBtn.classList.remove('selected');
            stopBtn.classList.add('unselected');

            simulatorStartBtn.disabled = false;
            simulatorStartBtn.classList.remove('unselected');
            simulatorStartBtn.classList.add('selected');
            
            simulatorStopBtn.disabled = true;
            simulatorStopBtn.classList.remove('selected');
            simulatorStopBtn.classList.add('unselected');
        }
    },

    toggleBoxSize(elementId){
        const box = document.querySelector(elementId);
        const button = document.querySelector(`${elementId} .minimize_div button`);
        if (box.classList.contains('minimize')) {
            box.classList.remove('minimize');
            box.classList.add('maximize');
            button.innerHTML = '<i class="fa-solid fa-minus"></i>';
            console.log("called maximize")
        } else if (box.classList.contains('maximize')) {
            box.classList.remove('maximize');
            box.classList.add('minimize');
            button.innerHTML = '<i class="fa-solid fa-plus"></i>';
            console.log("called minimize")
        } else{
            console.log("Toggle error");
        }
    },

    minimizeBoard(elementId){
        const box = document.querySelector(elementId);
        if (box.classList.contains('maximize')) {
            this.toggleBoxSize(elementId)
            console.log("called minimize")
        }
    },

    toggleBoardVisibility(selector, label){
        const element = document.querySelector(selector);
        const displayLabel = document.querySelector(`.setting .display-setting .${label} .label-1`);
        const elementButton = document.querySelector(`.setting .display-setting .${label} button`);
        if (element.classList.contains('hidden')) {
            element.classList.remove('hidden');
            if (displayLabel)  displayLabel.innerHTML = 'display';
            if (elementButton) elementButton.innerHTML = 'Hide board';
        } else {
            element.classList.add('hidden');
            if (displayLabel) displayLabel.innerHTML = 'hidden';
            if (elementButton) elementButton.innerHTML = 'Display board';
        }   
    },

    hideBoard(selector, label){
        const element = document.querySelector(selector);
        if (! element.classList.contains('hidden')) {
            this.toggleBoardVisibility(selector, label)
        }  
    },

    showBoard(selector, label){
        const element = document.querySelector(selector);
        if (element.classList.contains('hidden')) {
            this.toggleBoardVisibility(selector, label)
        }  
    },

    
    selectLabel(labelNum){
        const element = document.querySelector(`#client-side .client-label-${labelNum}`);
        const elementText = document.querySelector(`#client-side .client-label-${labelNum} p`);
        if (element.classList.contains('selected')) {
            element.classList.remove('selected');
            elementText.innerHTML = "NONE";
        } else {
            element.classList.add('selected');
            elementText.innerHTML = "Selected";
        }
    },
}
